31	
32	export type IrcAccountConfig = {
33	  name?: string;
34	  enabled?: boolean;
35	  /**
36	   * Break-glass override: allow nick-only allowlist matching.
37	   * Default behavior requires host/user-qualified identities.
38	   */
39	  dangerouslyAllowNameMatching?: boolean;
40	  host?: string;
41	  port?: number;
42	  tls?: boolean;
43	  nick?: string;
44	  username?: string;
45	  realname?: string;
46	  password?: string;
47	  passwordFile?: string;
48	  nickserv?: IrcNickServConfig;
49	  dmPolicy?: DmPolicy;
50	  allowFrom?: Array<string | number>;
51	  defaultTo?: string;
52	  groupPolicy?: GroupPolicy;
53	  groupAllowFrom?: Array<string | number>;
54	  groups?: Record<string, IrcChannelConfig>;
